const fs = require\('fs'\);
const buf = fs.readFileSync\('src/lib/supabase/database.types.ts'\);
let text;
if \(buf[0] === 0xFF && buf[1] === 0xFE\) {
  text = buf.slice\(2\).toString\('utf16le'\);
} else {
  text = buf.toString\('utf16le'\);
}
